const CACHE_DIR = './data'
const CACHE_FILE = `${CACHE_DIR}/shopify-products.json`
const TOKEN_CACHE_FILE = `${CACHE_DIR}/shopify-token.json`
const KNOWN_PRODUCTS_FILE = `${CACHE_DIR}/known-products.json`

// ── Known Products Tracker ───────────────────────────────────
// Tracks product IDs we've already seen so new Shopify products
// can be flagged as "new" and get auto-generated images.

function readKnownProducts(): { knownIds: number[]; lastSyncAt: string } {
  if (!existsSync(KNOWN_PRODUCTS_FILE)) return { knownIds: [], lastSyncAt: '' }
  try {
    return JSON.parse(readFileSync(KNOWN_PRODUCTS_FILE, 'utf-8'))
  } catch { return { knownIds: [], lastSyncAt: '' } }
}

function writeKnownProducts(data: { knownIds: number[]; lastSyncAt: string }) {
  if (!existsSync(CACHE_DIR)) mkdirSync(CACHE_DIR, { recursive: true })
  writeFileSync(KNOWN_PRODUCTS_FILE, JSON.stringify(data, null, 2))
}

function markProductsAsKnown(ids: number[]) {
  const data = readKnownProducts()
  const merged = [...new Set([...data.knownIds, ...ids])]
  writeKnownProducts({ knownIds: merged, lastSyncAt: new Date().toISOString() })
}

const SHOPIFY_STORE = process.env.SHOPIFY_STORE_DOMAIN || ''
let SHOPIFY_TOKEN = process.env.SHOPIFY_ACCESS_TOKEN || ''
const SHOPIFY_CLIENT_ID = process.env.SHOPIFY_CLIENT_ID || ''
const SHOPIFY_CLIENT_SECRET = process.env.SHOPIFY_CLIENT_SECRET || ''
const SHOPIFY_API = `https://${SHOPIFY_STORE}/admin/api/2024-10`

const SHOPIFY_SCOPES = 'read_products,write_products,read_inventory,write_inventory,read_content,write_content,read_orders,write_orders,read_fulfillments,write_fulfillments'

interface TokenCache {
  accessToken: string
  expiresAt: number
  scope: string
}

function readTokenCache(): TokenCache | null {
  if (!existsSync(TOKEN_CACHE_FILE)) return null
  try {
    return JSON.parse(readFileSync(TOKEN_CACHE_FILE, 'utf-8'))
  } catch { return null }
}

function writeTokenCache(data: TokenCache) {
  if (!existsSync(CACHE_DIR)) mkdirSync(CACHE_DIR, { recursive: true })
  writeFileSync(TOKEN_CACHE_FILE, JSON.stringify(data, null, 2))
}

function getActiveToken(): string {
  // Prefer cached token over env token (env token may be invalid/expired)
  const cached = readTokenCache()
  if (cached) {
    SHOPIFY_TOKEN = cached.accessToken
    return cached.accessToken
  }
  if (SHOPIFY_TOKEN) return SHOPIFY_TOKEN
  return ''
}

async function refreshAccessToken(): Promise<string> {
  const clientId = env('SHOPIFY_CLIENT_ID') || SHOPIFY_CLIENT_ID
  const clientSecret = env('SHOPIFY_CLIENT_SECRET') || SHOPIFY_CLIENT_SECRET
  if (!clientId || !clientSecret) throw new Error('Shopify OAuth credentials not configured')
  const res = await fetch(`https://${SHOPIFY_STORE}/admin/oauth/access_token`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      grant_type: 'client_credentials',
      client_id: clientId,
      client_secret: clientSecret,
    }),
  })
  const data = await res.json() as { access_token?: string; expires_in?: number; scope?: string; error?: string }
  if (!data.access_token) throw new Error(data.error ?? 'Token refresh failed')
  const cache: TokenCache = {
    accessToken: data.access_token,
    expiresAt: Date.now() + ((data.expires_in ?? 86399) - 300) * 1000,
    scope: data.scope ?? '',
  }
  writeTokenCache(cache)
  SHOPIFY_TOKEN = cache.accessToken
  console.log('[shopify] Token refreshed, expires in', data.expires_in, 'seconds')
  return cache.accessToken
}

async function ensureValidToken(): Promise<string> {
  const cached = readTokenCache()
  if (cached && cached.expiresAt > Date.now()) {
    return cached.accessToken
  }
  try {
    return await refreshAccessToken()
  } catch {
    return getActiveToken()
  }
}

const CACHE_MAX_AGE_MS = 5 * 60 * 1000 // 5 minutes

// ── Auto-Generate Product Image ──────────────────────────────
// Generates a high-quality product image using Together AI FLUX
// for newly discovered Shopify products.

function slugify(str: string): string {
  return str.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 80)
}

async function autoGenerateProductImage(product: ShopifyProduct): Promise<string | null> {
  if (!TOGETHER_API_KEY) {
    console.log('[auto-image] Together API key not configured, skipping')
    return null
  }

  const title = product.title
  const productType = product.product_type || ''
  const tags = typeof product.tags === 'string' ? product.tags : (product.tags ?? []).join(', ')

  const prompt = [
    `Professional product photography of "${title}",`,
    productType ? `${productType} car accessory,` : 'premium car accessory,',
    'clean studio lighting on white background,',
    'high-end commercial product photo,',
    'sharp focus, realistic, 8k quality,',
    'automotive product catalog style,',
    tags ? `themes: ${tags}` : '',
  ].filter(Boolean).join(' ')

  try {
    const res = await fetch('https://api.together.xyz/v1/images/generations', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${TOGETHER_API_KEY}`,
      },
      body: JSON.stringify({
        model: 'black-forest-labs/FLUX.1-schnell',
        prompt,
        width: 1024,
        height: 1024,
        n: 1,
        steps: 4,
        response_format: 'b64_json',
      }),
    })

    const data = await res.json() as any
    if (!res.ok) {
      console.error('[auto-image] Together API error:', data?.error?.message || res.status)
      return null
    }

    const imgData = data?.data?.[0]
    if (!imgData?.b64_json) {
      console.error('[auto-image] No image data in response')
      return null
    }

    const genDir = join(process.cwd(), 'generated-products')
    if (!existsSync(genDir)) mkdirSync(genDir, { recursive: true })

    const handle = slugify(title)
    const filename = `product-${handle}.png`
    const filePath = join(genDir, filename)

    const buffer = Buffer.from(imgData.b64_json, 'base64')
    writeFileSync(filePath, buffer)
    console.log(`[auto-image] Generated image for "${title}" → ${filename}`)

    // Force rebuild the generated image map
    generatedImageMap = null

    return filename
  } catch (err: any) {
    console.error('[auto-image] Failed:', err.message)
    return null
  }
}

// ── Generated Image Lookup ────────────────────────────────────
// Build a map of product index → local generated image filename
// so shapeProduct can prefer local images over Shopify CDN ones.

function buildGeneratedImageMap(): Map<number, string> {
  const map = new Map<number, string>()
  const genDir = `${process.cwd()}/generated-products`
  if (!existsSync(genDir)) return map
  try {
    const files = readdirSync(genDir).filter(f => f.endsWith('.png') || f.endsWith('.jpg'))
    for (const file of files) {
      const match = file.match(/^product-(\d{3})-/)
      if (match) {
        const idx = parseInt(match[1], 10)
        map.set(idx, file)
      }
    }
  } catch {}
  return map
}

let generatedImageMap: Map<number, string> | null = null

// Hard-coded overrides for products that don't follow the product-XXX pattern
const HANDLE_OVERRIDES: Record<string, string> = {
  'foldable-car-windshield-sun-shade-umbrella-uv-protection-heat-insulation-parasol-auto-front-window-cover-interior-protector-summer-gadgets': 'product-sun-shade-foldable-windshield.png',
}

function getGeneratedImageMap(): Map<number, string> {
  if (!generatedImageMap) generatedImageMap = buildGeneratedImageMap()
  return generatedImageMap
}

async function shopifyFetch(path: string): Promise<any> {
  if (!SHOPIFY_STORE) throw new Error('Shopify store not configured')
  const token = await ensureValidToken()
  if (!token) throw new Error('Shopify not configured — no access token available')
  const res = await fetch(`${SHOPIFY_API}${path}`, {
    headers: { 'X-Shopify-Access-Token': token },
  })
  if (!res.ok) throw new Error(`Shopify API ${res.status}: ${await res.text()}`)
  return res.json()
}

async function fetchAllShopifyProducts(): Promise<ShopifyProduct[]> {
  const allProducts: ShopifyProduct[] = []
  let lastId: number | undefined
  while (true) {
    const sinceParam = lastId ? `&since_id=${lastId}` : ''
    const data = await shopifyFetch(`/products.json?limit=250${sinceParam}`)
    const products = data.products ?? []
    allProducts.push(...products)
    if (products.length < 250) break
    lastId = products[products.length - 1].id
  }
  return allProducts
}

function readCache(): { products: ReturnType<typeof shapeProduct>[], syncedAt: string } | null {
  if (!existsSync(CACHE_FILE)) return null
  try {
    const raw = readFileSync(CACHE_FILE, 'utf-8')
    const data = JSON.parse(raw)
    const age = Date.now() - new Date(data.syncedAt).getTime()
    if (age < CACHE_MAX_AGE_MS && data.products?.length > 0) return data
  } catch {}
  return null
}

function writeCache(products: ReturnType<typeof shapeProduct>[]) {
  if (!existsSync(CACHE_DIR)) mkdirSync(CACHE_DIR, { recursive: true })
  // Guard against truncated API responses shrinking a healthy cache,
  // but still allow legitimate deletions (small drops of a few products).
  if (existsSync(CACHE_FILE)) {
    try {
      const existing = JSON.parse(readFileSync(CACHE_FILE, 'utf-8'))
      const existingCount = existing.products?.length ?? 0
      if (existingCount > 0 && products.length > 0 && products.length < existingCount - 5) {
        // Only block if the drop is large (likely a truncated response)
        return
      }
    } catch {}
  }
  writeFileSync(CACHE_FILE, JSON.stringify({ products, syncedAt: new Date().toISOString() }, null, 2))
}

function decodeHtmlEntities(str: string): string {
  return str
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&amp;/g, '&').replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'").replace(/&#x27;/g, "'")
    .replace(/&nbsp;/g, ' ')
}

function shapeProduct(p: any) {
  const decodedHtml = decodeHtmlEntities(p.body_html ?? '')
  const genMap = getGeneratedImageMap()

  let images = (p.images ?? [])
    .sort((a: any, b: any) => (a.position ?? 0) - (b.position ?? 0))
    .map((img: any) => ({
      id: img.id,
      src: img.src,
      alt: img.alt ?? p.title,
      width: img.width ?? 600,
      height: img.height ?? 600,
    }))

  // Prefer local generated images over Shopify CDN ones
  // Strategy 0: hard-coded handle overrides
  const handleOverride = HANDLE_OVERRIDES[p.handle]
  if (handleOverride && images.length > 0) {
    images = [{ id: images[0].id, src: `/api/generated-images/${handleOverride}`, alt: images[0].alt ?? p.title, width: images[0].width ?? 600, height: images[0].height ?? 600 }, ...images.slice(1)]
  } else {
  // Strategy 1: match by product-XXX-lifestyle pattern in existing image URLs
  let replaced = false
  for (const img of images) {
    const lifestyleMatch = img.src.match(/product-(\d{3})-lifestyle/)
    if (lifestyleMatch) {
      const idx = parseInt(lifestyleMatch[1], 10)
      const localFile = genMap.get(idx)
      if (localFile) {
        const localImg = { id: img.id, src: `/api/generated-images/${localFile}`, alt: img.alt ?? p.title, width: img.width ?? 600, height: img.height ?? 600 }
        images = [localImg, ...images.filter(i => i.id !== img.id)]
        replaced = true
        break
      }
    }
  }
  // Strategy 2: check if any generated file matches by product title keywords
  if (!replaced && images.length > 0) {
    const titleLower = p.title.toLowerCase()
    for (const [idx, file] of genMap) {
      const fileLower = file.toLowerCase()
      const keywords = titleLower.split(/\s+/).filter((w: string) => w.length > 3)
      const matchCount = keywords.filter((k: string) => fileLower.includes(k)).length
      if (matchCount >= 2) {
        const localImg = { id: images[0].id, src: `/api/generated-images/${file}`, alt: images[0].alt ?? p.title, width: images[0].width ?? 600, height: images[0].height ?? 600 }
        images = [localImg, ...images.slice(1)]
        break
      }
    }
  }
  }

  return {
    id: p.id,
    title: p.title,
    handle: p.handle,
    description: decodedHtml.replace(/<[^>]*>/g, '').trim(),
    htmlDescription: decodedHtml,
    vendor: p.vendor ?? 'DriveKit',
    productType: p.product_type ?? '',
    tags: typeof p.tags === 'string' ? p.tags.split(',').map((t: string) => t.trim()).filter(Boolean) : (p.tags ?? []),
    images,
    variants: (p.variants ?? []).map((v: any) => ({
      id: v.id,
      title: v.title,
      price: parseFloat(v.price),
      compareAtPrice: v.compare_at_price ? parseFloat(v.compare_at_price) : null,
      option1: v.option1,
      option2: v.option2,
      option3: v.option3,
      inStock: v.inventory_policy === 'continue' || (v.inventory_quantity ?? 0) > 0,
      inventoryQuantity: v.inventory_quantity ?? 0,
      sku: v.sku,
      grams: v.grams,
      weight: v.weight,
      weightUnit: v.weight_unit,
      imageId: v.image_id,
    })),
    options: (p.options ?? []).map((o: any) => ({
      name: o.name,
      values: o.values ?? [],
    })),
    minPrice: Math.min(...(p.variants ?? []).map((v: any) => parseFloat(v.price))),
    inStock: (p.variants ?? []).some((v: any) => v.inventory_policy === 'continue' || (v.inventory_quantity ?? 0) > 0),
  }
}

async function fetchAndCacheProducts() {
  try {
    const rawProducts = await fetchAllShopifyProducts()
    console.log(`[background-refresh] Found ${rawProducts.length} products from Shopify`)
    const shaped = rawProducts.filter((p) => p.status === 'active').map(shapeProduct)
    writeCache(shaped)
  } catch (err) {
    console.error('[background-refresh] Error:', err)
  }
}

