// Read .env file into a map so SMTP config is picked up even if the server
// process started before the vars were added to the file.
function loadDotEnv(): Record<string, string> {
  const vars: Record<string, string> = {}
  try {
    const raw = existsSync('.env') ? readFileSync('.env', 'utf-8') : ''
    for (const line of raw.split('\n')) {
      const trimmed = line.trim()
      if (!trimmed || trimmed.startsWith('#')) continue
      const eqIdx = trimmed.indexOf('=')
      if (eqIdx < 0) continue
      const key = trimmed.slice(0, eqIdx).trim()
      const val = trimmed.slice(eqIdx + 1).trim()
      vars[key] = val
    }
  } catch {}
  return vars
}

function env(key: string): string | undefined {
  if (process.env[key]) return process.env[key]
  return loadDotEnv()[key]
}

function getResendConfig() {
  const apiKey = env('RESEND_API_KEY')
  if (!apiKey) return null
  return {
    apiKey,
    from: env('FROM_EMAIL') ?? 'DriveKit <orders@resend.dev>',
  }
}

// Keep for backward compat — checks Resend config instead of SMTP
function getSmtpConfig() {
  const config = getResendConfig()
  if (!config) return null
  return {
    host: 'resend',
    port: 443,
    secure: true,
    auth: { user: 'resend', pass: config.apiKey },
    from: config.from,
  }
}

async function sendEmail(to: string, subject: string, html: string, type = 'general'): Promise<{ ok: boolean; error?: string }> {
  const config = getResendConfig()
  if (!config) {
    console.log(`[email] Resend not configured — skipping ${type} email to ${to}`)
    return { ok: false, error: 'Email not configured (set RESEND_API_KEY in .env)' }
  }
  try {
    const { Resend } = await import('resend')
    const resend = new Resend(config.apiKey)
    const fromAddress = config.from.includes('<') ? config.from : `DriveKit <${config.from}>`
    await resend.emails.send({ from: fromAddress, to, subject, html })

    await prisma.emailLog.create({ data: { to, subject, type, status: 'sent' } }).catch(() => {})
    console.log(`[email] Sent ${type} email to ${to}: ${subject}`)
    return { ok: true }
  } catch (err: any) {
    console.error(`[email] Failed to send ${type} to ${to}:`, err.message)
    await prisma.emailLog.create({ data: { to, subject, type, status: 'failed' } }).catch(() => {})
    return { ok: false, error: err.message }
  }
}

function parseToolResponse(result: { ok: boolean; data?: unknown; error?: string }) {
  if (!result.ok) return null
  if (result.data && typeof result.data === 'object') return result.data
  const rawStr = String(result.data ?? '')
  const truncIdx = rawStr.indexOf('\n\n[⚠️ TRUNCATED')
  const jsonStr = truncIdx > 0 ? rawStr.slice(0, truncIdx) : rawStr
  try { return JSON.parse(jsonStr) } catch { return null }
}

app.get('/shopify/sync', async (c) => {
  try {
    await requireAdmin(c)
  } catch (e: any) {
    if (e?.status) return c.json({ error: e.message }, e.status)
    return c.json({ error: e.message ?? String(e) }, 500)
  }

  try {
    const rawProducts = await fetchAllShopifyProducts()
    const shaped = rawProducts.filter((p) => p.status === 'active').map(shapeProduct)
    writeCache(shaped)

    // Detect new products and auto-generate images
    const known = readKnownProducts()
    const knownSet = new Set(known.knownIds)
    const activeRaw = rawProducts.filter(p => p.status === 'active')
    const newProducts = activeRaw.filter(p => !knownSet.has(p.id))

    const newProductTitles: string[] = []
    const generatedImages: string[] = []

    if (newProducts.length > 0) {
      console.log(`[sync] Found ${newProducts.length} new products!`)

      // Auto-generate images for new products (in parallel, max 3 at a time)
      for (let i = 0; i < newProducts.length; i += 3) {
        const batch = newProducts.slice(i, i + 3)
        const results = await Promise.allSettled(batch.map(p => autoGenerateProductImage(p)))
        for (const r of results) {
          if (r.status === 'fulfilled' && r.value) generatedImages.push(r.value)
        }
      }
    }

    // Mark ALL active products as known
    markProductsAsKnown(activeRaw.map(p => p.id))

    console.log(`[sync] Synced ${shaped.length} products from Shopify, ${newProducts.length} new, ${generatedImages.length} images generated`)
    return c.json({
      synced: true,
      count: shaped.length,
      newCount: newProducts.length,
      newProductTitles: newProducts.map(p => p.title),
      generatedImages,
      products: shaped,
    })
  } catch (err: any) {
    console.error('[sync] Error:', err)
    return c.json({ error: err.message ?? 'Sync failed' }, 500)
  }
})



app.get('/shopify/products', async (c) => {
  // Always try cache first — even if expired — so the UI always shows products
  try {
    if (existsSync(CACHE_FILE)) {
      const raw = readFileSync(CACHE_FILE, 'utf-8')
      const data = JSON.parse(raw)
      if (data.products?.length > 0) {
        const age = Date.now() - new Date(data.syncedAt).getTime()
        const source = age < CACHE_MAX_AGE_MS ? 'cache' : 'cache-stale'
        // Serve stale cache immediately; trigger background refresh if stale
        if (age >= CACHE_MAX_AGE_MS) {
          // Background fire-and-forget refresh — don't block the response
          fetchAndCacheProducts().catch(() => {})
        }
        // Add isNew flag based on known products tracker
        const known = readKnownProducts()
        const lastSync = known.lastSyncAt ? new Date(known.lastSyncAt).getTime() : 0
        const products = data.products.map((p: any) => ({
          ...p,
          // A product is "new" if it was synced AFTER the last known sync
          // and we haven't marked it as known yet
          isNew: known.knownIds.length > 0 && !known.knownIds.includes(p.id) && lastSync > 0,
        }))
        return c.json({ products, source, syncedAt: data.syncedAt })
      }
    }
  } catch {}

  // No cache at all — try live fetch as last resort
  try {
    const rawProducts = await fetchAllShopifyProducts()
    const products = rawProducts.filter((p) => p.status === 'active').map(shapeProduct)
    writeCache(products)
    return c.json({ products, source: 'live' })
  } catch {}

  return c.json({ products: [], error: 'No products available' }, 503)
})

app.get('/shopify/products/:handle', async (c) => {
  const handle = c.req.param('handle')

  // Try cache first
  const cached = readCache()
  if (cached) {
    const product = cached.products.find((p) => p.handle === handle)
    if (product) return c.json({ product })
  }

  // Fall back to direct Shopify API search
  try {
    const rawProducts = await fetchAllShopifyProducts()
    const found = rawProducts.find((p) => p.handle === handle)
    if (found) return c.json({ product: shapeProduct(found) })
  } catch {}

  return c.json({ error: 'Product not found' }, 404)
})

app.get('/shopify/checkout', async (c) => {
  const cartParam = c.req.query('cart')
  const promoCode = c.req.query('promo')
  if (!cartParam) return c.json({ error: 'Missing cart parameter' }, 400)

  try {
    const cart = JSON.parse(cartParam) as Array<{ variantId: number; quantity: number }>
    if (!Array.isArray(cart) || cart.length === 0) {
      return c.json({ error: 'Cart must be a non-empty array' }, 400)
    }

    const domain = SHOPIFY_STORE
    if (!domain) return c.json({ error: 'Shopify store not configured' }, 502)

    const items = cart
      .filter((item) => item.variantId && item.quantity > 0)
      .map((item) => `${item.variantId}:${item.quantity}`)
      .join(',')

    if (!items) return c.json({ error: 'No valid items in cart' }, 400)

    let url = `https://${domain}/cart/${items}`
    if (promoCode) {
      url += `?discount=${encodeURIComponent(promoCode)}`
    }

    return c.json({ url })
  } catch (err) {
    return c.json({ error: 'Failed to build checkout URL' }, 500)
  }
})

