// ── Auth ──────────────────────────────────────────────────────

function hashPassword(password: string): string {
  return createHash('sha256').update(password).digest('hex')
}

// ── Stateless Token System ────────────────────────────────────
// Tokens encode userId + HMAC signature so they survive server restarts.
// Format: base64url(userId).hex(hmac-sha256(userId, secret))

const TOKEN_SECRET = process.env.TOKEN_SECRET || 'drivekit-session-secret-2026'

function signToken(userId: string): string {
  const payload = Buffer.from(userId).toString('base64url')
  const sig = createHash('sha256').update(`${payload}:${TOKEN_SECRET}`).digest('hex').slice(0, 32)
  return `${payload}.${sig}`
}

function verifyToken(token: string): string | null {
  const sepIdx = token.lastIndexOf('.')
  if (sepIdx < 0) return null
  const payload = token.slice(0, sepIdx)
  const sig = token.slice(sepIdx + 1)
  const expected = createHash('sha256').update(`${payload}:${TOKEN_SECRET}`).digest('hex').slice(0, 32)
  if (sig !== expected) return null
  try {
    return Buffer.from(payload, 'base64url').toString()
  } catch { return null }
}

function generateToken(): string {
  return randomBytes(32).toString('hex')
}

// In-memory session cache for fast repeated lookups (not required for auth, just perf)
const sessions = new Map<string, { userId: string; email: string; role: string; createdAt: number }>()
const SESSION_MAX_AGE_MS = 7 * 24 * 60 * 60 * 1000 // 7 days

// ── Pending Signup Codes (in-memory, 10 min expiry) ──────────────
const CODE_EXPIRY_MS = 10 * 60 * 1000
const pendingSignups = new Map<string, { code: string; email: string; passwordHash: string; name: string | null; emailOptIn: boolean; expiresAt: number }>()

function generateSixDigitCode(): string {
  return String(Math.floor(100000 + Math.random() * 900000))
}

function cleanExpiredSessions() {
  const now = Date.now()
  for (const [token, session] of sessions) {
    if (now - session.createdAt > SESSION_MAX_AGE_MS) sessions.delete(token)
  }
}

app.post('/auth/signup', async (c) => {
  const body = await c.req.json<{ email?: string; password?: string; name?: string; emailOptIn?: boolean }>()
  const email = body.email?.trim().toLowerCase()
  const password = body.password
  const name = body.name?.trim() || null
  const emailOptIn = body.emailOptIn !== false

  if (!email || !password) {
    return c.json({ error: 'Email and password are required' }, 400)
  }

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
  if (!emailRegex.test(email)) {
    return c.json({ error: 'Invalid email address' }, 400)
  }

  if (password.length < 6) {
    return c.json({ error: 'Password must be at least 6 characters' }, 400)
  }

  const existing = await prisma.user.findUnique({ where: { email } })
  if (existing) {
    return c.json({ error: 'An account with this email already exists' }, 409)
  }

  const user = await prisma.user.create({
    data: { email, passwordHash: hashPassword(password), name },
  })

  // Persist emailOptIn via raw SQL (works even if the running Prisma client hasn't reloaded)
  if (emailOptIn === false) {
    await prisma.$executeRaw`UPDATE users SET email_opt_in = 0 WHERE id = ${user.id}`
  }

  cleanExpiredSessions()
  const token = signToken(user.id)
  sessions.set(token, { userId: user.id, email: user.email, role: user.role, createdAt: Date.now() })

  // Send verification email (always, regardless of opt-in)
  const verifyToken = randomBytes(32).toString('hex')
  await prisma.$executeRaw`UPDATE users SET verification_token = ${verifyToken} WHERE id = ${user.id}`
  const verifyUrl = `/api/auth/verify-email?token=${verifyToken}&email=${encodeURIComponent(user.email)}`
  const verifyHtml = emailHtmlWrapper('Verify Your Email', `
    <h2 style="color:#fff;font-size:20px;margin:16px 0 8px;">Verify your email address ✉️</h2>
    <p style="color:#ccc;font-size:14px;line-height:1.6;">Click below to verify your DriveKit account email. This confirms you own this inbox and helps us keep your account secure.</p>
    <p style="margin-top:16px;"><a href="${verifyUrl}" style="display:inline-block;padding:12px 24px;background:#dc2626;color:#fff;text-decoration:none;border-radius:6px;font-weight:600;">Verify My Email</a></p>
    <p style="color:#888;font-size:12px;margin-top:24px;">This link expires in 24 hours. If you didn't create a DriveKit account, ignore this email.</p>
  `)
  sendEmail(user.email, 'Verify your DriveKit email ✉️', verifyHtml, 'verification').catch(() => {})

  // Send welcome email + subscribe to newsletter if opted in
  if (emailOptIn !== false) {
    const welcomeHtml = emailHtmlWrapper('Welcome to DriveKit', `
      <h2 style="color:#fff;font-size:20px;margin:16px 0 8px;">Welcome to DriveKit${name ? ', ' + name : ''}! 🎉</h2>
      <p style="color:#ccc;font-size:14px;line-height:1.6;">You're now part of the DriveKit family. Here's what you can expect:</p>
      <ul style="color:#ccc;font-size:14px;line-height:2;">
        <li>🏎️ Exclusive deals and early access to new products</li>
        <li>📦 Order tracking and account management</li>
        <li>⭐ Reviews and recommendations from fellow drivers</li>
      </ul>
      <p style="margin-top:16px;"><a href="https://drivekit.com" style="display:inline-block;padding:12px 24px;background:#dc2626;color:#fff;text-decoration:none;border-radius:6px;font-weight:600;">Shop Now</a></p>
    `)
    sendEmail(user.email, 'Welcome to DriveKit! 🎉', welcomeHtml, 'welcome').catch(() => {})

    // Auto-subscribe to newsletter
    prisma.newsletterSubscriber.upsert({
      where: { email: user.email },
      update: { userId: user.id, name: user.name, unsubscribed: false, unsubscribedAt: null },
      create: { email: user.email, userId: user.id, name: user.name, source: 'signup' },
    }).catch(() => {})
  }

  return c.json({
    ok: true,
    token,
    user: { id: user.id, email: user.email, name: user.name, role: user.role },
  })
})

