app.post('/orders/place', async (c) => {
  const sessionUser = await getSessionUser(c)
  const body = await c.req.json<{
    email?: string
    items?: Array<{ productId: string; variantId?: string; title: string; variantTitle?: string; quantity: number; price: number }>
    shipping?: { name: string; address1: string; address2?: string; city: string; state: string; zip: string; country: string }
    promoCode?: string
    discount?: number
    total?: number
  }>()

  if (!body.email || !body.items?.length || !body.total) {
    return c.json({ error: 'Missing required fields' }, 400)
  }

  let orderNumber = generateOrderNumber()
  while (await prisma.order.findUnique({ where: { orderNumber } })) {
    orderNumber = generateOrderNumber()
  }

  const order = await prisma.order.create({
    data: {
      orderNumber,
      userId: sessionUser?.userId ?? null,
      email: body.email,
      status: 'pending',
      total: body.total,
      shippingName: body.shipping?.name,
      shippingAddress1: body.shipping?.address1,
      shippingAddress2: body.shipping?.address2,
      shippingCity: body.shipping?.city,
      shippingState: body.shipping?.state,
      shippingZip: body.shipping?.zip,
      shippingCountry: body.shipping?.country,
      promoCode: body.promoCode,
      discount: body.discount ?? 0,
    },
  })

  for (const item of body.items) {
    await prisma.orderItem.create({
      data: {
        orderId: order.id,
        productId: item.productId,
        variantId: item.variantId,
        title: item.title,
        variantTitle: item.variantTitle,
        quantity: item.quantity,
        price: item.price,
        total: item.price * item.quantity,
      },
    })
  }

  const fullOrder = await prisma.order.findUnique({ where: { id: order.id }, include: { items: true } })
  return c.json({ ok: true, order: { id: fullOrder!.id, orderNumber: fullOrder!.orderNumber, status: fullOrder!.status, total: fullOrder!.total } })
})

