app.get('/order/:orderNumber', async (c) => {
  const orderNumber = c.req.param('orderNumber')
  const sessionUser = await getSessionUser(c)

  const order = await prisma.order.findUnique({
    where: { orderNumber },
    include: { items: true, user: { select: { id: true, email: true, name: true } } },
  })

  if (!order) return c.json({ error: 'Order not found' }, 404)

  if (sessionUser && (sessionUser.userId === order.userId || sessionUser.role === 'OWNER' || sessionUser.role === 'ADMIN')) {
    return c.json({ order })
  }

  if (sessionUser && sessionUser.userId !== order.userId && sessionUser.role === 'CUSTOMER') {
    return c.json({ error: 'Forbidden' }, 403)
  }

  return c.json({ order })
})

