app.get('/reviews/product/:productId', async (c) => {
  const productId = c.req.param('productId')
  const reviews = await prisma.review.findMany({
    where: { productId },
    orderBy: { createdAt: 'desc' },
  })
  const count = reviews.length
  const avg = count > 0 ? reviews.reduce((sum, r) => sum + r.rating, 0) / count : 0
  const distribution = [0, 0, 0, 0, 0]
  reviews.forEach(r => { if (r.rating >= 1 && r.rating <= 5) distribution[r.rating - 1]++ })
  return c.json({ reviews, count, average: Math.round(avg * 10) / 10, distribution })
})

app.post('/reviews/product/:productId', async (c) => {
  const productId = c.req.param('productId')
  const body = await c.req.json()
  const { rating, title, body: reviewBody, displayName, email } = body

  if (!rating || rating < 1 || rating > 5) {
    return c.json({ error: 'Rating must be between 1 and 5' }, 400)
  }
  if (!displayName || !displayName.trim()) {
    return c.json({ error: 'Name is required' }, 400)
  }

  let userId: string | null = null
  const sessionUser = await getSessionUser(c)
  if (sessionUser) userId = sessionUser.userId

  const review = await prisma.review.create({
    data: {
      productId: String(productId),
      userId,
      displayName: displayName.trim(),
      email: email || sessionUser?.email || null,
      rating: Number(rating),
      title: title?.trim() || null,
      body: reviewBody?.trim() || '',
      verified: false,
    },
  })

  if (userId) {
    const hasOrder = await prisma.order.findFirst({
      where: {
        userId,
        items: { some: { productId: String(productId) } },
        status: { in: ['confirmed', 'shipped', 'delivered', 'fulfilled'] },
      },
    })
    if (hasOrder) {
      await prisma.review.update({ where: { id: review.id }, data: { verified: true } })
      review.verified = true
    }
  }

  return c.json({ ok: true, data: review }, 201)
})

