const HIGGSFIELD_KEY_ID = process.env.HIGGSFIELD_API_KEY_ID || '650cfce4-d06e-4609-91d4-acdb446883e5'
const HIGGSFIELD_SECRET = process.env.HIGGSFIELD_API_KEY_SECRET || 'aa7175928222606b424a1103ef8e9d2464e7ec3bc0ffc2d86cf83a04f7b5c4fe'
const HIGGSFIELD_API = 'https://platform.higgsfield.ai'
const TOGETHER_API_KEY = process.env.TOGETHER_API_KEY || 'tgp_v1_DUGfdMLXKqciq-p56rOJHqgo8SQ-W_5-OnVhk5Bp5dI'

interface HiggsfieldStyle {
  id: string
  name: string
  preview_url?: string
  [key: string]: unknown
}

let cachedStyles: HiggsfieldStyle[] | null = null
let stylesCacheAt = 0

async function fetchHiggsfieldStyles(): Promise<HiggsfieldStyle[]> {
  if (cachedStyles && Date.now() - stylesCacheAt < 30 * 60 * 1000) return cachedStyles
  const res = await fetch(`${HIGGSFIELD_API}/v1/text2image/soul-styles`, {
    headers: { 'hf-api-key': HIGGSFIELD_KEY_ID, 'hf-secret': HIGGSFIELD_SECRET },
  })
  if (!res.ok) throw new Error(`Failed to fetch styles: ${res.status}`)
  const data = await res.json() as HiggsfieldStyle[]
  cachedStyles = data
  stylesCacheAt = Date.now()
  return data
}

async function higgsfieldGenerate(params: {
  prompt: string
  style_id?: string
  width_and_height?: string
  quality?: string
  batch_size?: number
  seed?: number
}): Promise<{ images: Array<{ url: string }>; job_id?: string }> {
  const body = {
    prompt: params.prompt,
    style_id: params.style_id || '1cb4b936-77bf-4f9a-9039-f3d349a4cdbe',
    width_and_height: params.width_and_height || '1536x1536',
    quality: params.quality || '720p',
    batch_size: params.batch_size || 1,
    seed: params.seed ?? Math.floor(Math.random() * 999999),
  }

  const res = await fetch(`${HIGGSFIELD_API}/v1/text2image/soul`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'hf-api-key': HIGGSFIELD_KEY_ID,
      'hf-secret': HIGGSFIELD_SECRET,
    },
    body: JSON.stringify({ params: body }),
  })

  const data = await res.json() as any

  if (!res.ok) {
    const msg = data?.detail || data?.error || `Generation failed (${res.status})`
    throw new Error(msg)
  }

  const images = (data?.images ?? data?.output?.images ?? data?.result?.images ?? []).map((img: any) => ({
    url: typeof img === 'string' ? img : img?.url || img?.image_url || '',
  })).filter((img: { url: string }) => img.url)

  if (images.length === 0 && data?.job_id) {
    const jobId = data.job_id
    for (let i = 0; i < 30; i++) {
      await new Promise(r => setTimeout(r, 2000))
      const pollRes = await fetch(`${HIGGSFIELD_API}/v1/jobs/${jobId}`, {
        headers: { 'hf-api-key': HIGGSFIELD_KEY_ID, 'hf-secret': HIGGSFIELD_SECRET },
      })
      if (!pollRes.ok) continue
      const pollData = await pollRes.json() as any
      const status = pollData?.status || pollData?.state
      if (status === 'completed' || status === 'succeeded') {
        const resultImages = (pollData?.images ?? pollData?.output?.images ?? pollData?.result?.images ?? []).map((img: any) => ({
          url: typeof img === 'string' ? img : img?.url || img?.image_url || '',
        })).filter((img: { url: string }) => img.url)
        if (resultImages.length > 0) return { images: resultImages, job_id: jobId }
        break
      }
      if (status === 'failed' || status === 'error') {
        throw new Error(pollData?.error || 'Generation failed')
      }
    }
  }

  return { images, job_id: data?.job_id }
}

