async function togetherGenerate(params: {
  prompt: string
  width?: number
  height?: number
  referenceImages?: string[]
}): Promise<{ images: Array<{ url: string }>; model: string }> {
  if (!TOGETHER_API_KEY) throw new Error('Together API key not configured')

  const hasRef = params.referenceImages && params.referenceImages.length > 0

  const payload: Record<string, any> = {
    model: hasRef ? 'black-forest-labs/FLUX.2-pro' : 'black-forest-labs/FLUX.1-schnell',
    prompt: params.prompt,
    width: params.width ?? 1024,
    height: params.height ?? 1024,
    n: 1,
    response_format: 'b64_json',
  }

  if (!hasRef) {
    payload.steps = 4
  }

  if (hasRef) {
    payload.reference_images = params.referenceImages
  }

  const res = await fetch('https://api.together.xyz/v1/images/generations', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${TOGETHER_API_KEY}`,
    },
    body: JSON.stringify(payload),
  })

  const data = await res.json() as any

  if (!res.ok) {
    const msg = data?.error?.message || data?.detail || `Together API failed (${res.status})`
    throw new Error(msg)
  }

  const images = (data?.data ?? []).map((img: any) => {
    if (img.b64_json) {
      return { url: `data:image/png;base64,${img.b64_json}` }
    }
    return { url: img.url || '' }
  }).filter((img: { url: string }) => img.url)

  return { images, model: hasRef ? 'FLUX.2-pro' : 'FLUX.1-schnell' }
}

function generatePlaceholderSvg(prompt: string, width: number, height: number, seed: number): string {
  const colors = ['#7c3aed', '#2563eb', '#059669', '#d97706', '#dc2626', '#8b5cf6', '#0891b2']
  const pick = (i: number) => colors[(seed + i) % colors.length]
  const c1 = pick(0), c2 = pick(3), c3 = pick(5)
  const words = prompt.split(/\s+/).slice(0, 6)
  const displayPrompt = words.length > 0 ? words.join(' ') : prompt.slice(0, 40)

  return `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">
  <defs>
    <linearGradient id="bg" x1="0%" y1="0%" x2="100%" y2="100%">
      <stop offset="0%" style="stop-color:${c1};stop-opacity:1" />
      <stop offset="50%" style="stop-color:${c2};stop-opacity:1" />
      <stop offset="100%" style="stop-color:${c3};stop-opacity:1" />
    </linearGradient>
    <filter id="noise" x="0%" y="0%" width="100%" height="100%">
      <feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" seed="${seed}" />
      <feColorMatrix type="saturate" values="0" />
      <feBlend in="SourceGraphic" mode="multiply" result="blend" />
    </filter>
  </defs>
  <rect width="${width}" height="${height}" fill="url(#bg)" />
  <circle cx="${width * 0.3}" cy="${height * 0.4}" r="${Math.min(width, height) * 0.25}" fill="${c2}" opacity="0.3" filter="url(#noise)" />
  <circle cx="${width * 0.7}" cy="${height * 0.6}" r="${Math.min(width, height) * 0.2}" fill="${c1}" opacity="0.25" filter="url(#noise)" />
  <rect x="${width * 0.08}" y="${height * 0.38}" width="${width * 0.84}" height="${height * 0.24}" rx="12" fill="rgba(0,0,0,0.5)" />
  <text x="${width / 2}" y="${height * 0.47}" text-anchor="middle" fill="white" font-family="system-ui,sans-serif" font-size="${Math.max(16, Math.min(32, width / 28))}" font-weight="600">${displayPrompt.replace(/&/g, '&amp;').replace(/</g, '&lt;')}</text>
  <text x="${width / 2}" y="${height * 0.57}" text-anchor="middle" fill="rgba(255,255,255,0.6)" font-family="system-ui,sans-serif" font-size="${Math.max(12, Math.min(18, width / 45))}">AI Image Preview · Higgsfield Soul V2</text>
</svg>`
}

app.post('/higgsfield/generate', async (c) => {
  const body = await c.req.json<{
    prompt?: string
    style_id?: string
    width_and_height?: string
    quality?: string
    batch_size?: number
    seed?: number
    reference_images?: string[]
  }>()

  if (!body.prompt?.trim()) {
    return c.json({ error: 'Prompt is required' }, 400)
  }

  const prompt = body.prompt.trim()
  const seed = body.seed ?? Math.floor(Math.random() * 999999)
  const w = body.width_and_height ? parseInt(body.width_and_height.split('x')[0]) || 1024 : 1024
  const h = body.width_and_height ? parseInt(body.width_and_height.split('x')[1]) || 1024 : 1024

  // Try Higgsfield API first
  if (HIGGSFIELD_KEY_ID && HIGGSFIELD_SECRET) {
    try {
      const result = await higgsfieldGenerate({
        prompt,
        style_id: body.style_id,
        width_and_height: body.width_and_height,
        quality: body.quality,
        batch_size: body.batch_size,
        seed,
      })
      if (result.images.length > 0) {
        return c.json({ ok: true, images: result.images, job_id: result.job_id, provider: 'higgsfield' })
      }
    } catch (err: any) {
      const msg = err.message ?? ''
      if (msg.includes('Not enough credits') || msg.includes('not_enough_credits')) {
        console.log('[generate] Higgsfield credits exhausted, trying Together AI')
      } else {
        console.log('[generate] Higgsfield error:', msg)
      }
    }
  }

  // Try Together AI (free FLUX.1-schnell, or FLUX.2-pro with reference images)
  if (TOGETHER_API_KEY) {
    try {
      const result = await togetherGenerate({
        prompt,
        width: w,
        height: h,
        referenceImages: body.reference_images,
      })
      if (result.images.length > 0) {
        return c.json({ ok: true, images: result.images, provider: 'together', model: result.model })
      }
    } catch (err: any) {
      console.log('[generate] Together AI error:', err.message)
    }
  }

  // Fallback: generate styled SVG preview
  const svg = generatePlaceholderSvg(prompt, w, h, seed)
  const base64 = Buffer.from(svg).toString('base64')
  const dataUrl = `data:image/svg+xml;base64,${base64}`
  return c.json({ ok: true, images: [{ url: dataUrl }], provider: 'preview', note: 'Preview image. Real AI generation via Together AI or Higgsfield requires valid API credentials.' })
})

