app.post('/newsletter/subscribe', async (c) => {
  const body = await c.req.json<{ email?: string; name?: string }>()
  const email = body.email?.trim().toLowerCase()
  const name = body.name?.trim() || null

  if (!email) return c.json({ error: 'Email is required' }, 400)
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
  if (!emailRegex.test(email)) return c.json({ error: 'Invalid email address' }, 400)

  const sessionUser = await getSessionUser(c)

  try {
    const existing = await prisma.newsletterSubscriber.findUnique({ where: { email } })
    if (existing && !existing.unsubscribed) {
      return c.json({ ok: true, message: 'You are already subscribed!' })
    }

    const subscriber = await prisma.newsletterSubscriber.upsert({
      where: { email },
      update: {
        unsubscribed: false,
        unsubscribedAt: null,
        name: name ?? existing?.name ?? null,
        userId: sessionUser?.userId ?? existing?.userId ?? null,
      },
      create: {
        email,
        name,
        userId: sessionUser?.userId ?? null,
        source: 'newsletter-form',
      },
    })

    const unsubToken = createHash('sha256').update(email + 'unsubscribe').digest('hex').slice(0, 16)
    const unsubUrl = `/api/newsletter/unsubscribe?token=${unsubToken}&email=${encodeURIComponent(email)}`

    const welcomeHtml = emailHtmlWrapper('Thanks for subscribing!', `
      <h2 style="color:#fff;font-size:20px;margin:16px 0 8px;">You're in! 🔔</h2>
      <p style="color:#ccc;font-size:14px;line-height:1.6;">Thanks for subscribing to the DriveKit newsletter. You'll be the first to know about:</p>
      <ul style="color:#ccc;font-size:14px;line-height:2;">
        <li>🔥 Flash sales and exclusive discounts</li>
        <li>🆕 New product launches</li>
        <li>🚗 Car care tips and driving essentials</li>
      </ul>
      <p style="color:#888;font-size:12px;margin-top:24px;">Don't want these emails? <a href="${unsubUrl}" style="color:#dc2626;">Unsubscribe</a></p>
    `)
    sendEmail(email, 'Welcome to the DriveKit Newsletter! 🔔', welcomeHtml, 'newsletter-welcome').catch(() => {})

    return c.json({ ok: true, message: 'Successfully subscribed!', subscriber: { id: subscriber.id, email: subscriber.email } })
  } catch (err: any) {
    console.error('[newsletter] Subscribe error:', err)
    return c.json({ error: 'Failed to subscribe' }, 500)
  }
})

app.get('/newsletter/unsubscribe', async (c) => {
  const email = c.req.query('email')?.toLowerCase().trim()
  const token = c.req.query('token')

  if (!email || !token) {
    return c.html('<html><body style="font-family:sans-serif;background:#111;color:#fff;padding:48px;text-align:center;"><h1>Invalid unsubscribe link</h1><p>Please check the link and try again.</p></body></html>')
  }

  const expectedToken = createHash('sha256').update(email + 'unsubscribe').digest('hex').slice(0, 16)
  if (token !== expectedToken) {
    return c.html('<html><body style="font-family:sans-serif;background:#111;color:#fff;padding:48px;text-align:center;"><h1>Invalid token</h1><p>This unsubscribe link is invalid.</p></body></html>')
  }

  try {
    await prisma.newsletterSubscriber.update({
      where: { email },
      data: { unsubscribed: true, unsubscribedAt: new Date() },
    })

    // Also disable emailOptIn on the User if they exist
    const user = await prisma.user.findUnique({ where: { email } })
    if (user) {
      await prisma.$executeRaw`UPDATE users SET email_opt_in = 0 WHERE id = ${user.id}`
    }

    return c.html(`<!DOCTYPE html><html><body style="font-family:sans-serif;background:#111;color:#fff;padding:48px;text-align:center;">
      <h1 style="font-size:28px;">You've been unsubscribed</h1>
      <p style="color:#ccc;margin-top:12px;">You won't receive any more marketing emails from DriveKit.</p>
      <p style="color:#888;margin-top:24px;font-size:14px;">Changed your mind? <a href="/" style="color:#dc2626;">Visit DriveKit</a> and subscribe again anytime.</p>
    </body></html>`)
  } catch (err: any) {
    console.error('[newsletter] Unsubscribe error:', err)
    return c.html('<html><body style="font-family:sans-serif;background:#111;color:#fff;padding:48px;text-align:center;"><h1>Something went wrong</h1><p>Please try again later.</p></body></html>')
  }
})

