app.post('/auth/send-verification', async (c) => {
  const authHeader = c.req.header('Authorization')
  const bearerToken = authHeader?.replace('Bearer ', '')
  const body = await c.req.json().catch(() => ({})) as Record<string, any>

  let email: string | null = null
  let user: { id: string; email: string; emailVerified: boolean } | null = null

  // Allow both authenticated and unauthenticated (login flow) verification requests
  if (bearerToken) {
    const session = sessions.get(bearerToken)
    if (session && Date.now() - session.createdAt < SESSION_MAX_AGE_MS) {
      const u = await prisma.user.findUnique({ where: { id: session.userId } })
      if (u) { user = { id: u.id, email: u.email, emailVerified: u.emailVerified }; email = u.email }
    }
  }

  if (!email && body.email && body.password) {
    const u = await prisma.user.findUnique({ where: { email: String(body.email).trim().toLowerCase() } })
    if (u && u.passwordHash === hashPassword(String(body.password))) {
      user = { id: u.id, email: u.email, emailVerified: u.emailVerified }; email = u.email
    }
  }

  if (!email) return c.json({ error: 'Authentication required' }, 401)

  const token = randomBytes(32).toString('hex')
  await prisma.$executeRaw`UPDATE users SET verification_token = ${token} WHERE id = ${user!.id}`

  const verifyUrl = `/api/auth/verify-email?token=${token}&email=${encodeURIComponent(email)}`

  const html = emailHtmlWrapper('Verify Your Email', `
    <h2 style="color:#fff;font-size:20px;margin:16px 0 8px;">Verify your email address ✉️</h2>
    <p style="color:#ccc;font-size:14px;line-height:1.6;">Click below to verify your DriveKit account email. This confirms you own this inbox and helps us keep your account secure.</p>
    <p style="margin-top:16px;"><a href="${verifyUrl}" style="display:inline-block;padding:12px 24px;background:#dc2626;color:#fff;text-decoration:none;border-radius:6px;font-weight:600;">Verify My Email</a></p>
    <p style="color:#888;font-size:12px;margin-top:24px;">This link expires in 24 hours. If you didn't create a DriveKit account, ignore this email.</p>
  `)

  const result = await sendEmail(email, 'Verify your DriveKit email ✉️', html, 'verification')
  if (result.ok) return c.json({ ok: true, message: 'Verification email sent' })
  return c.json({ ok: true, message: 'Verification email queued (SMTP not configured)' })
})

app.get('/auth/verify-email', async (c) => {
  const token = c.req.query('token')
  const email = c.req.query('email')?.toLowerCase().trim()

  if (!token || !email) {
    return c.html(`<!DOCTYPE html><html><body style="font-family:sans-serif;background:#111;color:#fff;padding:48px;text-align:center;">
      <h1 style="font-size:28px;color:#dc2626;">Invalid Link</h1>
      <p style="color:#ccc;margin-top:12px;">This verification link is invalid or missing required parameters.</p>
    </body></html>`)
  }

  const user = await prisma.user.findUnique({ where: { email } })
  if (!user || user.verificationToken !== token) {
    return c.html(`<!DOCTYPE html><html><body style="font-family:sans-serif;background:#111;color:#fff;padding:48px;text-align:center;">
      <h1 style="font-size:28px;color:#dc2626;">Verification Failed</h1>
      <p style="color:#ccc;margin-top:12px;">This link may have expired or already been used.</p>
    </body></html>`)
  }

  await prisma.$executeRaw`UPDATE users SET email_verified = 1, verification_token = NULL WHERE id = ${user.id}`

  return c.html(`<!DOCTYPE html><html><body style="font-family:sans-serif;background:#111;color:#fff;padding:48px;text-align:center;">
    <h1 style="font-size:28px;">Email Verified! ✅</h1>
    <p style="color:#ccc;margin-top:12px;">Your email address has been verified. Your DriveKit account is now fully activated.</p>
    <p style="margin-top:24px;"><a href="/" style="display:inline-block;padding:12px 24px;background:#dc2626;color:#fff;text-decoration:none;border-radius:6px;font-weight:600;">Back to DriveKit</a></p>
  </body></html>`)
})

