app.post('/admin/known-products/mark-all', async (c) => {
  try {
    await requireAdmin(c)
  } catch (e: any) {
    if (e?.status) return c.json({ error: e.message }, e.status)
    return c.json({ error: e.message ?? String(e) }, 500)
  }
  // Mark all currently cached products as known
  let products: any[] = []
  try {
    if (existsSync(CACHE_FILE)) {
      const raw = readFileSync(CACHE_FILE, 'utf-8')
      const data = JSON.parse(raw)
      products = data.products ?? []
    }
  } catch {}
  if (products.length === 0) {
    return c.json({ ok: true, marked: 0, message: 'No products in cache' })
  }
  markProductsAsKnown(products.map((p: any) => p.id))
  return c.json({ ok: true, marked: products.length })
})

app.post('/admin/known-products/reset', async (c) => {
  try {
    await requireAdmin(c)
  } catch (e: any) {
    if (e?.status) return c.json({ error: e.message }, e.status)
    return c.json({ error: e.message ?? String(e) }, 500)
  }
  // Reset known products — next sync will treat everything as new
  writeKnownProducts({ knownIds: [], lastSyncAt: '' })
  return c.json({ ok: true, message: 'Known products reset. Next sync will treat all products as new.' })
})

